SELECT * FROM (
    SELECT t.*, ROWNUM rn FROM (
        SELECT * FROM WORK_ORDER

            AND ORDER_TYPE = #{orderType}
            AND STATUS = #{status}
            AND HANDLER_ID = #{handlerId}
            AND PRIORITY = #{priority}

        ORDER BY CREATE_TIME DESC
    ) t WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}

SELECT COUNT(*) FROM WORK_ORDER

    AND ORDER_TYPE = #{orderType}
    AND STATUS = #{status}
    AND HANDLER_ID = #{handlerId}
    AND PRIORITY = #{priority}

